<template>
  <div class="overall">
    <!-- 游戏规则反馈提示 -->
    <el-dialog
      v-model="gameStatus.gameGuideVisible"
      title="猜拳游戏规则"
      class="dialog-rules"
      width="30%"
    >
      <img
        src="../assets/images/image-rules.svg"
        alt=""
        class="dialog-rules-img"
      />
      <h3>
        在游戏开始之前，您必须连接钱包，并且设置钱包的网络为 Rinkeby，
        断开连接后游戏结束。
      </h3>
    </el-dialog>
    <!-- 提示需要连接到指定的测试网 -->
    <el-alert
      v-if="gameStatus.isConnect && chainId != 4"
      title="钱包需要连接 Rinkeby 网络"
      type="error"
      effect="dark"
    />
    <!-- 测试网钱包需要有测试币 -->
    <el-alert
      v-if="gameStatus.isConnect && chainId == 4 && myBalance == 0"
      title="账户的测试币为 0，请到 https://faucets.chain.link/rinkeby，获取测试币"
      type="error"
      effect="dark"
    />
    <!-- 这里设置加载反馈，避免打包过程中用户使劲点 -->
    <el-container
      v-loading.fullscreen="gameStatus.pending"
      element-loading-text="等待矿工打包..."
      :element-loading-spinner="svg"
      element-loading-svg-view-box="-10, -10, 50, 50"
      element-loading-background="rgba(0, 0, 0, 0.8)"
    >
      <el-header class="nav">
        <!-- 导航栏信息 -->
        <el-row>
          <!-- 设置logo -->
          <el-col :span="12" style="display: flex">
            <a href="/" style="display: flex; text-decoration: none">
              <img
                src="../assets/images/header-logo.png"
                alt="logo"
                class="header-logo"
              />
              <h1 class="Header-logo-wordmark">以太坊猜拳</h1></a
            >
            <!-- 设置是否连接网络提示 -->
            <el-icon class="connect-indicator"
              ><turn-off
                v-if="!gameStatus.isConnect"
                style="color: #fcdf35" /><open
                v-else
                style="color: green" /></el-icon
            ><span v-if="!gameStatus.isConnect" class="connect-indicator-mark"
              >Not Connect</span
            >
            <!-- 连接的地址提示和余额提示 -->
            <span v-else class="connect-indicator-mark">
              Connected to {{ userAddress }} at
              {{ chainId == 4 ? "Rinkeby" : "Unsupport" }}
              <br />
              Your balance:
              {{ myBalance }}
            </span>
          </el-col>
          <!-- 添加游戏说明 -->
          <el-col :span="12" class="nav-right"
            ><el-button
              type="primary"
              size="large"
              @click="gameStatus.gameGuideVisible = true"
              style="margin-top: 16px"
              ><el-icon><guide /></el-icon>游戏指南</el-button
            >
            <!-- 连接钱包 -->
            <el-button
              v-if="!gameStatus.isConnect"
              type="success"
              size="large"
              style="margin-top: 16px; margin-right: 25px"
              @click="handleWalletConnect"
              >连接钱包</el-button
            >
            <!-- 如果已经连接了，设置断开连接 -->
            <el-button
              v-if="gameStatus.isConnect"
              type="success"
              size="large"
              style="margin-top: 16px; margin-right: 25px"
              @click="resetApp"
              >断开连接</el-button
            >
          </el-col>
        </el-row>
      </el-header>

      <el-container>
        <el-main class="main">
          <!-- 分数栏 -->
          <el-row style="justify-content: center">
            <el-col :span="10" class="score-bar">
              <img src="../assets/images/logo.svg" alt="logo" />
              <!-- 得分板 -->
              <div class="score-wrapper">
                <!-- 玩家得分板 -->
                <div class="score-container">
                  <h4>Your score</h4>
                  <p>{{ gameStatus.userScore }}</p>
                </div>
                <!-- 电脑得分板 -->
                <div class="score-container">
                  <h4>Computer score</h4>
                  <p>{{ gameStatus.computerScore }}</p>
                </div>
              </div>
            </el-col>
          </el-row>
          <!-- 选择石头、剪刀、布 -->
          <el-row
            style="justify-content: center"
            class="main-choice"
            v-if="!gameStatus.getResult"
          >
            <el-button
              type="primary"
              class="btn-circle btn-paper pick"
              circle
              @click="select(2)"
            >
              <span class="wrapper">
                <img
                  src="../assets/images/icon-paper.svg"
                  alt="paper icon"
                /> </span
            ></el-button>
            <el-button
              class="btn-circle btn-scissors pick"
              type="primary"
              @click="select(0)"
            >
              <span class="wrapper">
                <img
                  src="../assets/images/icon-scissors.svg"
                  alt="scissors icon"
                />
              </span>
            </el-button>
            <el-button
              class="btn-circle btn-rock pick"
              type="button"
              @click="select(2)"
            >
              <span class="wrapper">
                <img src="../assets/images/icon-rock.svg" alt="rock icon" />
              </span>
            </el-button>
          </el-row>
          <!-- 用于显示结果 -->
          <div
            class="selection"
            style="display: grid"
            v-if="gameStatus.getResult"
          >
            <!-- 玩家出招 -->
            <div class="user_choice">
              <h2>You picked</h2>
              <el-button
                class="btn-circle"
                :class="{
                  'btn-paper': gameStatus.userC == 2,
                  'btn-rock': gameStatus.userC == 1,
                  'btn-scissors': gameStatus.userC == 0,
                }"
                type="plain"
              >
                <span class="wrapper">
                  <img
                    v-if="gameStatus.userC == 2"
                    src="../assets/images/icon-paper.svg"
                    alt="paper icon"
                  />
                  <img
                    v-else-if="gameStatus.userC == 0"
                    src="../assets/images/icon-scissors.svg"
                    alt="paper icon"
                  />
                  <img
                    v-else-if="gameStatus.userC == 1"
                    src="../assets/images/icon-rock.svg"
                    alt="paper icon"
                  />
                </span>
              </el-button>
            </div>
            <!-- 显示win, lost, draw -->
            <div class="result-text">
              <h1>You {{ gameStatus.isWin }}</h1>
              <el-button
                class="btn-reset"
                type="primary"
                plain
                @click="play_again"
                >play again</el-button
              >
            </div>
            <!-- 电脑出招 -->
            <div class="computer_choice">
              <h2>The house picked</h2>
              <el-button
                class="btn-circle"
                :class="{
                  'btn-paper': gameStatus.computerC == 2,
                  'btn-rock': gameStatus.computerC == 1,
                  'btn-scissors': gameStatus.computerC == 0,
                }"
                type="primary"
              >
                <span class="wrapper">
                  <img
                    v-if="gameStatus.computerC == 2"
                    src="../assets/images/icon-paper.svg"
                    alt="paper icon"
                  />
                  <img
                    v-else-if="gameStatus.computerC == 0"
                    src="../assets/images/icon-scissors.svg"
                    alt="paper icon"
                  />
                  <img
                    v-else-if="gameStatus.computerC == 1"
                    src="../assets/images/icon-rock.svg"
                    alt="paper icon"
                  />
                </span>
              </el-button>
            </div>
          </div>
        </el-main>
      </el-container>
    </el-container>
  </div>
</template>

<script setup>
// 引入库
import { computed, reactive, ref, watch } from "vue";
// 引入web3.js工具类
import { utils } from "web3";
//引入钱包组件
import useWallet from "../hooks/useWallte";
// 引入合约的json ABI
import { ABI } from "../web3/abis";
// 引入合约的地址
import { ADDRESS } from "../web3/config";
// 引入获取链外随机数的工具函数
import { getNumbers } from "../random/randomNumers.js";
import { ElMessage } from "element-plus";
const {
  onConnect, // 初始化 web3modal 和 web3
  connected, // 是否连接钱包
  web3, // 导出初始化后的 web3
  userAddress, //连接地址
  chainId, //链id
  networkId, //网络id
  resetApp, //断开连接
  assets, //资产，可以拓展为ERC20代币，但是由于时间关系没有继续
} = useWallet();
const gameStatus = reactive({
  isConnect: false, //是否连接钱包
  userScore: 0, //玩家得分
  computerScore: 0, //电脑得分
  gameGuideVisible: false, //是否打开导航栏
  getResult: false, //是否已经从测试链获得结果
  isWin: "win", //猜拳结果显示
  userC: 1, //用户的选择，0 is scissors, 1 is rock, 2 is paper
  computerC: 0, //电脑的选择，0 is scissors, 1 is rock, 2 is paper
  pending: false, //用于控制页面加载
});
const wrongClick = () => {
  ElMessage({
    message: "需要连接钱包才能开始游戏",
    type: "warning",
  });
};

// 自定义的加载SVG图标
const svg = `
        <path class="path" d="
          M 30 15
          L 28 17
          M 25.61 25.61
          A 15 15, 0, 0, 1, 15 30
          A 15 15, 0, 1, 1, 27.99 7.5
          L 15 15
        " style="stroke-width: 4px; fill: rgba(0, 0, 0, 0)"/>
      `;
// 创建合约实例
const contract = computed(() => new web3.value.eth.Contract(ABI, ADDRESS));
// 获取向合约传入链下随机数，然后生成链上随机数
const randomNumbers = async () => {
  let numbers = await getNumbers();
  gameStatus.pending = true;
  let result = await contract.value.methods
    .createRandom(numbers)
    .send({ from: userAddress.value });
  console.log("the random seed is", numbers);
  console.log("random number is", result.events.randomNumber.returnValues);
  return result.events.randomNumber.returnValues[0];
};
// 继续游戏
const play_again = () => {
  gameStatus.getResult = false;
};
// 用户选择结果后执行逻辑
const select = async (user_choice) => {
  if (!gameStatus.isConnect) {
    wrongClick();
    return;
  }

  //0 is scissors, 1 is rock, 2 is paper
  //获取结果
  //获取链上随机数
  let computer_choice = await randomNumbers();
  let result;
  // 更新动态响应
  gameStatus.userC = user_choice;
  gameStatus.computerC = computer_choice;
  // 结果判断
  if (user_choice == computer_choice) {
    result = "draw";
  } else if (
    (user_choice == 2 && computer_choice == 1) ||
    (user_choice == 1 && computer_choice == 0) ||
    (user_choice == 0 && computer_choice == 2)
  ) {
    result = "win";
  } else {
    result = "lost";
  }
  //设置结果
  if (result == "win") {
    gameStatus.userScore++;
    gameStatus.isWin = "win";
  } else if (result == "lost") {
    gameStatus.computerScore++;
    gameStatus.isWin = "lost";
  }
  // 更新组件状态
  gameStatus.isWin = result;
  gameStatus.getResult = true;
  gameStatus.pending = false;
};
// 处理连接钱包
const handleWalletConnect = async () => {
  await onConnect();
  if (connected) {
    console.log("successfully connect");
  }
};
// 监听连接状态
watch(connected, () => {
  // console.log("watch", connected.value);
  gameStatus.isConnect = connected.value;
});

// 因为默认钱包提供数值精确到小数点9位, 这里设置成小数点6位
const myBalance = computed(() => {
  return Math.floor(assets.value * 1000000) / 1000000;
});
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
@import "../css/styles.css";
@import "../css/font.css";
</style>
